def validate(args, output):
    stamp, target = args
    if not isinstance(output, list):
        return False
    # empty output only valid if target itself is somehow reachable with 0 stamps... only if stamp==target and len==1? No: empty means no way.
    # actually empty array means cannot obtain target — but problem says always solvable given constraints, so empty is wrong
    # However if for some reason input is trivially target==stamp and output==[], that could be wrong too.
    # The problem guarantees a solution exists, so empty list should only be returned if genuinely impossible.
    # We treat empty as invalid (all given inputs have solutions).
    if len(output) == 0:
        return False
    if len(output) > 10 * len(target):
        return False
    # Simulate: start with '?' * len(target), apply stamps in given order
    s = list('?' * len(target))
    for idx in output:
        if not isinstance(idx, int):
            return False
        if idx < 0 or idx + len(stamp) > len(target):
            return False
        for k in range(len(stamp)):
            s[idx + k] = stamp[k]
    return ''.join(s) == target

