function validate(args, output) {
    const [stamp, target] = args;
    if (!Array.isArray(output) || output.length === 0) return false;
    if (output.length > 10 * target.length) return false;
    const s = Array(target.length).fill('?');
    for (const idx of output) {
        if (typeof idx !== 'number') return false;
        if (idx < 0 || idx + stamp.length > target.length) return false;
        for (let k = 0; k < stamp.length; k++) s[idx + k] = stamp[k];
    }
    return s.join('') === target;
}

