def gen(rng, size):
    import string
    stamp_len = rng.randint(2, max(2, size // 5))
    target_len = rng.randint(stamp_len, max(stamp_len, size))
    stamp = ''.join(rng.choice(string.ascii_lowercase[:4]) for _ in range(stamp_len))
    # build target by repeatedly stamping
    target = list('?' * target_len)
    for _ in range(10 * target_len):
        pos = rng.randint(0, target_len - stamp_len)
        for k in range(stamp_len):
            target[pos + k] = stamp[k]
        if '?' not in target:
            break
    if '?' in target:
        # fill remaining with stamp at 0
        for k in range(stamp_len):
            target[k] = stamp[k]
    return [stamp, ''.join(target)]

