class Solution:
    def movesToStamp(self, stamp: str, target: str):
        m, n = len(stamp), len(target)
        t = list(target)
        result = []
        total_replaced = 0
        def try_stamp(pos):
            count = 0
            for k in range(m):
                if t[pos + k] == '?':
                    continue
                if t[pos + k] != stamp[k]:
                    return 0
                count += 1
            # replace
            for k in range(m):
                if t[pos + k] != '?':
                    t[pos + k] = '?'
            return count
        changed = True
        while changed:
            changed = False
            for pos in range(n - m + 1):
                replaced = try_stamp(pos)
                if replaced > 0:
                    total_replaced += replaced
                    result.append(pos)
                    changed = True
                    if total_replaced == n:
                        return result[::-1]
        return [] if total_replaced < n else result[::-1]

