var movesToStamp = function(stamp, target) {
    const m = stamp.length, n = target.length;
    const t = target.split('');
    const result = [];
    let total = 0;
    let changed = true;
    while (changed) {
        changed = false;
        for (let pos = 0; pos <= n - m; pos++) {
            let cnt = 0, ok = true;
            for (let k = 0; k < m; k++) {
                if (t[pos+k] === '?') continue;
                if (t[pos+k] !== stamp[k]) { ok = false; break; }
                cnt++;
            }
            if (ok && cnt > 0) {
                for (let k = 0; k < m; k++) t[pos+k] = '?';
                total += cnt;
                result.push(pos);
                changed = true;
                if (total === n) return result.reverse();
            }
        }
    }
    return total < n ? [] : result.reverse();
};
